import React from 'react';
import { Outlet, NavLink, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../utils/AuthContext';

const navSections = [
  {
    label: 'Overview',
    items: [
      { to: '/dashboard', icon: '⬡', label: 'Dashboard' },
      { to: '/profile', icon: '◎', label: 'My Profile' },
    ]
  },
  {
    label: 'AI Features',
    items: [
      { to: '/mock-interview', icon: '◈', label: 'Mock Interview', badge: 'AI' },
      { to: '/company-match', icon: '◉', label: 'Company Match', badge: 'AI' },
      { to: '/roadmap', icon: '◐', label: '30-Day Roadmap', badge: 'AI' },
      { to: '/leaderboard', icon: '◆', label: 'Leaderboard' },
    ]
  },
  {
    label: 'Practice Tests',
    items: [
      { to: '/tests/coding', icon: '⟨⟩', label: 'Coding Test' },
      { to: '/tests/aptitude', icon: '∑', label: 'Aptitude Test' },
      { to: '/tests/communication', icon: '◎', label: 'Communication' },
    ]
  },
  {
    label: 'More',
    items: [
      { to: '/resources', icon: '⊞', label: 'Resources' },
      { to: '/results', icon: '▣', label: 'My Results' },
    ]
  }
];

export default function Layout() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();

  const handleLogout = () => { logout(); navigate('/login'); };

  const getPageTitle = () => {
    const path = location.pathname;
    if (path.includes('dashboard')) return 'Dashboard';
    if (path.includes('profile')) return 'My Profile';
    if (path.includes('mock-interview')) return 'AI Mock Interview';
    if (path.includes('company-match')) return 'Company Match';
    if (path.includes('roadmap')) return '30-Day Roadmap';
    if (path.includes('leaderboard')) return 'Leaderboard';
    if (path.includes('coding')) return 'Coding Test';
    if (path.includes('aptitude')) return 'Aptitude Test';
    if (path.includes('communication')) return 'Communication Test';
    if (path.includes('resources')) return 'Resources';
    if (path.includes('results')) return 'My Results';
    return 'PlaceAI';
  };

  return (
    <div className="app-container">
      <aside className="sidebar">
        {/* Logo */}
        <div className="sidebar-logo">
          <div className="logo-icon">🎯</div>
          <span className="logo-text">PlaceAI</span>
        </div>

        {/* Nav */}
        <nav className="sidebar-nav">
          {navSections.map((section, si) => (
            <div key={si}>
              {si > 0 && <div className="nav-divider" />}
              <div className="nav-section-label">{section.label}</div>
              {section.items.map(item => (
                <NavLink
                  key={item.to}
                  to={item.to}
                  className={({ isActive }) => `nav-item${isActive ? ' active' : ''}`}
                >
                  <span className="nav-icon">{item.icon}</span>
                  <span className="nav-label">{item.label}</span>
                  {item.badge && <span className="nav-badge">{item.badge}</span>}
                </NavLink>
              ))}
            </div>
          ))}
        </nav>

        {/* User */}
        <div className="sidebar-bottom">
          <div className="user-card" onClick={handleLogout} title="Click to logout">
            <div className="user-avatar">
              {user?.name?.[0]?.toUpperCase() || 'U'}
            </div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div className="user-name" style={{ overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>
                {user?.name}
              </div>
              <div className="user-role">Sign out</div>
            </div>
            <span style={{ fontSize: 13, color: 'var(--text3)', flexShrink: 0 }}>→</span>
          </div>
        </div>
      </aside>

      <main className="main-content">
        {/* Top bar */}
        <div style={{
          height: 58,
          background: 'rgba(12,17,33,0.85)',
          backdropFilter: 'blur(12px)',
          borderBottom: '1px solid var(--border)',
          display: 'flex',
          alignItems: 'center',
          padding: '0 32px',
          justifyContent: 'space-between',
          position: 'sticky',
          top: 0,
          zIndex: 50,
        }}>
          <div style={{ display:'flex', alignItems:'center', gap:10 }}>
            <span style={{ fontSize: 12, color: 'var(--text3)' }}>PlaceAI</span>
            <span style={{ fontSize: 12, color: 'var(--text3)' }}>/</span>
            <span style={{ fontSize: 13, fontWeight: 600, color: 'var(--text2)' }}>{getPageTitle()}</span>
          </div>
          <div style={{ display:'flex', alignItems:'center', gap:10 }}>
            <div style={{
              display:'flex', alignItems:'center', gap:7,
              background: 'var(--surface)',
              border: '1px solid var(--border)',
              borderRadius: 100,
              padding: '5px 12px 5px 8px',
              fontSize: 12,
              color: 'var(--text2)',
              fontWeight: 500
            }}>
              <div style={{
                width: 20, height: 20, borderRadius: '50%',
                background: 'linear-gradient(135deg, var(--indigo), var(--violet))',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: 10, fontWeight: 700, color: 'white'
              }}>
                {user?.name?.[0]?.toUpperCase() || 'U'}
              </div>
              {user?.name?.split(' ')[0]}
            </div>
          </div>
        </div>

        <Outlet />
      </main>
    </div>
  );
}
